// ── Approximate label/pulse centers for each live state ──
const STATE_CENTERS: Record<string, { x: number; y: number }> = {
  wa: { x: 107, y: 50 },
  or: { x: 116, y: 133 },
  ca: { x: 80, y: 290 },
  id: { x: 185, y: 105 },
  mt: { x: 280, y: 95 },
  co: { x: 318, y: 275 },
  az: { x: 185, y: 370 },
  mi: { x: 650, y: 185 },
  pa: { x: 790, y: 215 },
  wv: { x: 745, y: 280 },
  va: { x: 780, y: 295 },
  ky: { x: 680, y: 315 },
  tn: { x: 660, y: 345 },
  nc: { x: 770, y: 340 },
}

export default function USMap({ stateFlowMap, stateConditions }: Props) {
  const router = useRouter()
  const [tooltip, setTooltip] = useState<Tooltip | null>(null)
  const [hovered, setHovered] = useState<string | null>(null)

  const onClick = (id: string) => {
    const key = toKey(id)
    if (LIVE_STATES.has(key)) router.push(`/state/${key}`)
  }

  const onEnter = (e: React.MouseEvent<SVGPathElement>, id: string, name: string) => {
    const key = toKey(id)
    const live = LIVE_STATES.has(key)
    const count = live ? (STATES[key]?.rivers.length ?? 0) : 0
    const r = e.currentTarget.closest('svg')!.getBoundingClientRect()
    const cond = stateFlowMap?.[key]
    const summary = stateConditions?.[key]
    setTooltip({ x: e.clientX - r.left, y: e.clientY - r.top - 16, name, count, live, cond, summary })
    setHovered(id)
  }

  const onMove = (e: React.MouseEvent<SVGPathElement>) => {
    const r = e.currentTarget.closest('svg')?.getBoundingClientRect()
    if (r) setTooltip(t => t ? { ...t, x: e.clientX - r.left, y: e.clientY - r.top - 16 } : null)
  }

  const ev = (id: string, name: string) => ({
    onMouseEnter: (e: React.MouseEvent<SVGPathElement>) => onEnter(e, id, name),
    onMouseLeave: () => { setTooltip(null); setHovered(null) },
    onMouseMove: onMove,
    onClick: () => onClick(id),
  })

  // Live state path rendering — colored by flow condition
  const lp = (id: string, name: string, d: string) => {
    const h = hovered === id
    const key = toKey(id)
    const cond = stateFlowMap?.[key]
    const colors = (cond && COND_FILL[cond]) || DEFAULT_FILL
    return (
      <path key={id} id={id} d={d}
        fill={h ? colors.hover : colors.base}
        stroke={h ? 'rgba(255,255,255,1)' : 'rgba(255,255,255,0.8)'}
        strokeWidth={h ? 1.4 : 0.8}
        cursor="pointer"
        style={{ transition: 'fill .14s, filter .14s', filter: h ? 'drop-shadow(0 2px 6px rgba(0,80,50,.4))' : 'none' }}
        {...ev(id, name)}
      />
    )
  }

  // Coming-soon path rendering
  const sp = (id: string, name: string, d: string) => {
    const h = hovered === id
    return (
      <path key={id} id={id} d={d}
        fill={h ? '#c4c0b8' : '#d8d4cc'}
        stroke="rgba(255,255,255,0.6)"
        strokeWidth={0.55}
        cursor="default"
        style={{ transition: 'fill .1s' }}
        {...ev(id, name)}
      />
    )
  }

  const pulse = (cx: number, cy: number, dur: string) => (
    <g key={`p${cx}${cy}`} style={{ pointerEvents: 'none' }}>
      <circle cx={cx} cy={cy} r={3.5} fill="#1db971" opacity={0.95} />
      <circle cx={cx} cy={cy} r={3.5} fill="#1db971" opacity={0.38}>
        <animate attributeName="r" from="3.5" to="10" dur={dur} repeatCount="indefinite" />
        <animate attributeName="opacity" from="0.38" to="0" dur={dur} repeatCount="indefinite" />
      </circle>
    </g>
  )

  const lbl = (x: number, y: number, text: string) => (
    <text key={`l${text}`} x={x} y={y}
      fontFamily="IBM Plex Mono,monospace" fontSize={7} fontWeight="700"
      fill="#08385a" textAnchor="middle" pointerEvents="none"
      style={{ userSelect: 'none' }}>
      {text}
    </text>
  )

  // Separate live vs coming-soon states
  const liveIds = new Set(['WA', 'OR', 'CA', 'ID', 'MT', 'CO', 'AZ', 'MI', 'PA', 'WV', 'VA', 'KY', 'TN', 'NC'])

  return (
    <div style={{ position: 'relative', width: '100%', height: '100%' }}>
      <svg viewBox="0 0 959 593" xmlns="http://www.w3.org/2000/svg"
        style={{ width: '100%', height: '100%', display: 'block', borderRadius: '10px', boxShadow: '0 6px 32px rgba(0,0,0,.22)' }}>
        <defs>
          <radialGradient id="ocean" cx="50%" cy="45%" r="60%">
            <stop offset="0%" stopColor="#2e6a9a" />
            <stop offset="100%" stopColor="#152d42" />
          </radialGradient>
          <pattern id="hatching" patternUnits="userSpaceOnUse" width="3" height="3" patternTransform="rotate(45)">
            <line x1="0" y1="0" x2="0" y2="3" stroke="rgba(255,255,255,0.04)" strokeWidth="1" />
          </pattern>
        </defs>

        {/* Ocean */}
        <rect width="959" height="593" rx="10" fill="url(#ocean)" />
        {/* Subtle latitude lines */}
        {[100, 160, 220, 280, 340, 400, 460].map(y => (
          <line key={y} x1="20" y1={y} x2="940" y2={y} stroke="rgba(255,255,255,0.035)" strokeWidth="1" />
        ))}

        {/* ── COMING-SOON STATES (render first so live states layer on top) ── */}
        {Object.entries(STATE_PATHS).map(([id, { name, d }]) => {
          if (liveIds.has(id) || id === 'AK' || id === 'HI') return null
          return sp(id, name, d)
        })}

        {/* ── LIVE STATES ── */}
        {Object.entries(STATE_PATHS).map(([id, { name, d }]) => {
          if (!liveIds.has(id)) return null
          return lp(id, name, d)
        })}

        {/* ── LIVE STATE LABELS ── */}
        {Object.entries(STATE_CENTERS).map(([key, { x, y }]) => (
          lbl(x, y + 4, key.toUpperCase())
        ))}

        {/* ── PULSE DOTS on live states ── */}
        {Object.entries(STATE_CENTERS).map(([, { x, y }], i) => (
          pulse(x, y - 4, `${2.0 + (i % 7) * 0.1}s`)
        ))}

        {/* ── Alaska / Hawaii insets ── */}
        <g>
          <rect x="16" y="445" width="155" height="100" rx="6" fill="#163347" stroke="rgba(255,255,255,0.12)" strokeWidth={0.7} />
          <g transform="translate(-120,335) scale(0.35)">
            <path d={STATE_PATHS.AK.d}
              fill="#d8d4cc" stroke="rgba(255,255,255,0.6)" strokeWidth={1.2}
              style={{ cursor: 'default' }}
              {...ev('AK', 'Alaska')}
            />
          </g>
          <text x="93" y="540" fontFamily="IBM Plex Mono,monospace" fontSize={8} fill="rgba(255,255,255,0.3)" textAnchor="middle">coming soon</text>
        </g>
        <g>
          <rect x="185" y="475" width="90" height="60" rx="6" fill="#163347" stroke="rgba(255,255,255,0.12)" strokeWidth={0.7} />
          <g transform="translate(-50,0) scale(0.9)">
            <path d={STATE_PATHS.HI.d}
              fill="#d8d4cc" stroke="rgba(255,255,255,0.6)" strokeWidth={0.8}
              style={{ cursor: 'default' }}
              {...ev('HI', 'Hawaii')}
            />
          </g>
          <text x="230" y="530" fontFamily="IBM Plex Mono,monospace" fontSize={8} fill="rgba(255,255,255,0.3)" textAnchor="middle">coming soon</text>
        </g>

        {/* ── Footer ── */}
        <text x="480" y="578" fontFamily="IBM Plex Mono,monospace" fontSize={8.5} fill="rgba(255,255,255,0.32)" textAnchor="middle">
          14 states live · WA · OR · ID · MT · CO · CA · MI · PA · WV · VA · KY · TN · NC · AZ — more added monthly
        </text>
      </svg>

      {/* Tooltip */}
      {tooltip && (
        <div style={{
          position: 'absolute', left: tooltip.x + 14, top: tooltip.y,
          background: 'var(--bg)', border: '.5px solid var(--bd2)',
          borderRadius: 'var(--r)', padding: '8px 13px',
          fontFamily: "'IBM Plex Mono', monospace",
          pointerEvents: 'none', boxShadow: '0 4px 18px rgba(0,0,0,.18)',
          zIndex: 50, whiteSpace: 'nowrap', maxWidth: '240px',
        }}>
          <div style={{ fontSize: '12px', fontWeight: 600, color: 'var(--rvdk)', marginBottom: '3px' }}>{tooltip.name}</div>
          {tooltip.live ? (
            <>
              <div style={{ fontSize: '10px', color: 'var(--rv)', marginBottom: tooltip.summary ? '5px' : 0 }}>● {tooltip.count} rivers · click to explore</div>
              {tooltip.summary && (
                <div style={{ fontSize: '9px', color: 'var(--tx2)', display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                  {tooltip.summary.optimal > 0 && <span style={{ color: 'var(--rv)' }}>● {tooltip.summary.optimal} optimal</span>}
                  {tooltip.summary.high > 0 && <span style={{ color: 'var(--am)' }}>● {tooltip.summary.high} high</span>}
                  {tooltip.summary.low > 0 && <span style={{ color: 'var(--lo)' }}>● {tooltip.summary.low} low</span>}
                  {tooltip.summary.flood > 0 && <span style={{ color: 'var(--dg)' }}>● {tooltip.summary.flood} flood</span>}
                </div>
              )}
            </>
          ) : (
            <div style={{ fontSize: '10px', color: 'var(--tx3)' }}>Coming soon</div>
          )}
        </div>
      )}

      {/* Legend */}
      <div style={{
        position: 'absolute', bottom: '16px', right: '14px',
        display: 'flex', gap: '14px',
        fontFamily: "'IBM Plex Mono', monospace", fontSize: '9px',
        color: 'rgba(255,255,255,0.55)',
      }}>
        {stateFlowMap ? (
          <>
            <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
              <div style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#6dc9a0' }} />
              Optimal
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
              <div style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#92c5de' }} />
              Low
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
              <div style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#e8b954' }} />
              High
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
              <div style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#e07070' }} />
              Flood
            </div>
          </>
        ) : (
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#92c5de' }} />
            Live data
          </div>
        )}
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <div style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#d8d4cc' }} />
          Coming soon
        </div>
      </div>
    </div>
  )
}
